mapper.select:
select id, owner_id, owner_name, visitor_name, visitor_phone,
       visit_time, leave_time, status, community_id,
       building, unit, room, create_time, update_time, remark
from community_visitor
where owner_id = #{ownerId}
  and owner_name like concat('%', #{ownerName}, '%')
  and visitor_name like concat('%', #{visitorName}, '%')
  and visitor_phone = #{visitorPhone}
  and status = #{status}
  and community_id = #{communityId}
  and building = #{building}
  and unit = #{unit}
  and room = #{room}
order by create_time desc
